export const CONTENT_HTML = "\r\n<p class=\"intro\">Hai bức tranh cùng chủ đề, cùng kỹ thuật, cùng màu sắc — nhưng một bức \"hút mắt\" ngay từ cái nhìn đầu tiên, bức kia thì không. Chín phần mười trường hợp, khác biệt nằm ở <strong>bố cục</strong>. Đây là yếu tố ẩn nhưng quyết định sự thành bại của mọi tác phẩm.</p>\r\n\r\n<div class=\"stats break-half\">\r\n  <div class=\"stat\"><div class=\"stat-num\">1.618</div><div class=\"stat-label\">Golden Ratio</div><div class=\"stat-sub\">Tỉ lệ vàng</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">7+</div><div class=\"stat-label\">Loại bố cục</div><div class=\"stat-sub\">Kinh điển</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">500y</div><div class=\"stat-label\">Lịch sử nghiên cứu</div><div class=\"stat-sub\">Từ Phục hưng</div></div>\r\n</div>\r\n\r\n<!-- ═════════════════════════════════════════════\r\n     01. ĐỊNH NGHĨA CHUNG\r\n     ═════════════════════════════════════════════ -->\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>01</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Định nghĩa</p>\r\n    <h2 class=\"div-title\">Bố cục là gì?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p><strong>Bố cục</strong> <em>(Composition)</em> là nghệ thuật sắp xếp các yếu tố thị giác — hình, khối, màu, sắc độ — trong một khuôn hình để tạo ra tổng thể có ý nghĩa và cảm xúc.</p>\r\n\r\n<p>Từ \"composition\" bắt nguồn từ tiếng Latin <em>componere</em> — \"đặt cùng nhau\". Bất kỳ tác phẩm thị giác nào — tranh, ảnh, poster, UI, phim — đều có bố cục. Chỉ khác là <strong>có chủ đích</strong> hay <strong>tình cờ</strong>.</p>\r\n\r\n<div class=\"gls\">\r\n  <p class=\"gls-head\">A — Thuật ngữ bố cục cơ bản</p>\r\n  <div class=\"gls-body\">\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Composition<small>Bố cục</small></p><p class=\"gls-def\">Cách tổ chức tổng thể các yếu tố trong khuôn hình.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Focal Point<small>Tâm điểm</small></p><p class=\"gls-def\">Điểm thu hút ánh nhìn đầu tiên.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Balance<small>Cân bằng</small></p><p class=\"gls-def\">Phân bố \"trọng lượng\" thị giác đều trong khung.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Rhythm<small>Nhịp điệu</small></p><p class=\"gls-def\">Sự lặp lại có quy luật tạo chuyển động cho mắt.</p></div>\r\n  </div>\r\n</div>\r\n\r\n<!-- IMG_01: bleed - Bố cục trong tranh vs không có bố cục -->\r\n<div class=\"bleed break\" data-img=\"IMG_01\">\r\n  <span class=\"bleed-kw-label\">🔍 IMG_01</span>\r\n  <p class=\"bleed-kw\">Good composition vs bad composition painting comparison</p>\r\n  <p class=\"bleed-note\">So sánh 2 tranh: cùng chủ đề, khác bố cục — một hút mắt, một không</p>\r\n  <span class=\"bleed-cap\">Fig. 01 · Impact of composition</span>\r\n</div>\r\n\r\n<!-- ═════════════════════════════════════════════\r\n     02. VAI TRÒ TRONG TRANH\r\n     ═════════════════════════════════════════════ -->\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>02</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Vai trò</p>\r\n    <h2 class=\"div-title\">Bố cục trong tranh làm gì?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Khác với thiết kế đồ họa (ưu tiên thông tin), bố cục trong hội họa phục vụ <strong>trải nghiệm thẩm mỹ và cảm xúc</strong>. Bốn nhiệm vụ chính:</p>\r\n\r\n<div class=\"pr-table\">\r\n  <div class=\"pr-row\"><span class=\"pr-i\">i.</span><div class=\"pr-n\">Dẫn mắt<small>Eye movement</small></div><div class=\"pr-d\">Đưa ánh nhìn người xem theo hành trình có chủ đích: từ focal → phụ → nền.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">ii.</span><div class=\"pr-n\">Tạo cảm xúc<small>Emotion</small></div><div class=\"pr-d\">Bố cục đối xứng → yên bình. Bất đối xứng → năng lượng. Đường chéo → kịch tính.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iii.</span><div class=\"pr-n\">Kể chuyện<small>Narrative</small></div><div class=\"pr-d\">Sắp xếp nhân vật và đối tượng để người xem \"đọc\" được câu chuyện.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iv.</span><div class=\"pr-n\">Tạo chiều sâu<small>Depth</small></div><div class=\"pr-d\">Lớp cảnh, phối cảnh khí quyển, tỉ lệ — tạo ảo giác không gian 3D trên mặt phẳng 2D.</div></div>\r\n</div>\r\n\r\n<!-- IMG_02: spread - Mona Lisa phân tích bố cục tam giác -->\r\n<div class=\"spread break-half\">\r\n  <div class=\"spread-text\">\r\n    <p class=\"spread-kicker\">Ví dụ cổ điển</p>\r\n    <h3 class=\"spread-title\">Mona Lisa — tam giác vàng</h3>\r\n    <p>Nhìn <strong>Mona Lisa</strong> của Leonardo da Vinci — cảm giác \"ổn định, kỳ lạ, cuốn hút\". Đó không phải do nụ cười — đó là do <em>bố cục tam giác cân</em>.</p>\r\n    <p>Cơ thể Mona Lisa tạo thành hình tam giác đáy rộng, đỉnh là đầu. Tam giác là hình học <strong>ổn định nhất</strong> trong tự nhiên — tạo cảm giác vững chắc, trường tồn.</p>\r\n    <p>Kết hợp với hậu cảnh xa mờ (phối cảnh khí quyển) và ánh nhìn trực diện, bố cục tam giác biến Mona Lisa thành biểu tượng bất tử.</p>\r\n  </div>\r\n  <div class=\"spread-img\" data-img=\"IMG_02\">\r\n    <span class=\"img-sub\">🔍 IMG_02</span>\r\n    <p class=\"img-kw\">Mona Lisa triangle composition analysis overlay</p>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"pq\">\r\n  <p class=\"pq-text\">Một bức tranh không có bố cục là <em>câu văn không có dấu chấm câu.</em></p>\r\n  <span class=\"pq-cite\">— Nguyên tắc hội hoạ cổ điển</span>\r\n</div>\r\n\r\n<!-- ═════════════════════════════════════════════\r\n     03. CÁC LOẠI BỐ CỤC CỔ ĐIỂN\r\n     ═════════════════════════════════════════════ -->\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>03</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Phân loại</p>\r\n    <h2 class=\"div-title\">7 loại bố cục kinh điển</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Các bậc thầy qua nhiều thế kỷ đã đúc kết 7 loại bố cục \"dùng được\" cho hầu hết tác phẩm hội hoạ:</p>\r\n\r\n<div class=\"el-intro\">\r\n  <div class=\"el-intro-n\">7</div>\r\n  <p class=\"el-intro-t\">Mỗi loại cho cảm xúc riêng — chọn theo chủ đề.</p>\r\n</div>\r\n\r\n<div class=\"el-list\">\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">01</span>\r\n      <p class=\"el-name\">Tam giác <em>Triangle</em></p>\r\n      <p class=\"el-desc\">Ổn định, trường tồn. Dùng cho chân dung cổ điển, tranh tôn giáo.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">02</span>\r\n      <p class=\"el-name\">Đường chéo <em>Diagonal</em></p>\r\n      <p class=\"el-desc\">Động, kịch tính. Dùng cho tranh trận chiến, chuyển động mạnh.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">03</span>\r\n      <p class=\"el-name\">Hình chữ S <em>S-curve</em></p>\r\n      <p class=\"el-desc\">Uyển chuyển, nữ tính. Dùng cho tranh phong cảnh, nhân vật nữ.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">04</span>\r\n      <p class=\"el-name\">Hình tròn <em>Circular</em></p>\r\n      <p class=\"el-desc\">Tập trung, hoàn chỉnh. Dùng cho chủ đề cô đọng, chân dung sát mặt.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">05</span>\r\n      <p class=\"el-name\">Hình chữ L <em>L-shape</em></p>\r\n      <p class=\"el-desc\">Ổn định có chỉ hướng. Dùng khi có tiền cảnh và hậu cảnh rõ.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">06</span>\r\n      <p class=\"el-name\">1/3 (Rule of Thirds) <em>Thirds</em></p>\r\n      <p class=\"el-desc\">Quy luật vàng của nhiếp ảnh, cũng áp dụng cho hội họa. Dễ, hiệu quả.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">07</span>\r\n      <p class=\"el-name\">Tỉ lệ vàng <em>Golden Ratio</em></p>\r\n      <p class=\"el-desc\">Phi (Φ = 1.618). Tỉ lệ toán học trong tự nhiên, dùng từ thời Hy Lạp cổ.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"></div>\r\n  </div>\r\n  <div class=\"el-item el-fill-end\">\r\n    <p class=\"el-fill-text\">Chọn loại<br>theo<br>cảm xúc<br>muốn truyền</p>\r\n  </div>\r\n</div>\r\n\r\n<!-- IMG_03: bleed - 7 sơ đồ bố cục overlay trên tranh cổ điển -->\r\n<div class=\"bleed break\" data-img=\"IMG_03\">\r\n  <span class=\"bleed-kw-label\">🔍 IMG_03</span>\r\n  <p class=\"bleed-kw\">Classical painting composition diagrams triangle diagonal s-curve</p>\r\n  <p class=\"bleed-note\">7 sơ đồ bố cục vẽ đè lên các tranh nổi tiếng — trực quan hoá lý thuyết</p>\r\n  <span class=\"bleed-cap\">Fig. 02 · 7 classical patterns</span>\r\n</div>\r\n\r\n<!-- ═════════════════════════════════════════════\r\n     04. TỶ LỆ VÀNG & RULE OF THIRDS\r\n     ═════════════════════════════════════════════ -->\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>04</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Đi sâu</p>\r\n    <h2 class=\"div-title\">Golden Ratio vs Rule of Thirds</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Hai quy luật phổ biến nhất trong bố cục. Khác nhau nhỏ nhưng có lịch sử khác biệt:</p>\r\n\r\n<div class=\"cmp break-half\">\r\n  <div class=\"cmp-col l\">\r\n    <p class=\"cmp-lbl\">Golden Ratio</p>\r\n    <p class=\"cmp-title\">Φ = 1.618</p>\r\n    <ul class=\"cmp-list\">\r\n      <li>Tỉ lệ toán học trong tự nhiên</li>\r\n      <li>Dùng từ Hy Lạp cổ (Parthenon)</li>\r\n      <li>Tinh tế, hài hòa, khó nhận ra</li>\r\n      <li>Đặt focal ở giao điểm Fibonacci</li>\r\n      <li>Phức tạp hơn, đòi hỏi tính toán</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"cmp-col r\">\r\n    <p class=\"cmp-lbl\">Rule of Thirds</p>\r\n    <p class=\"cmp-title\">1/3 - 2/3</p>\r\n    <ul class=\"cmp-list\">\r\n      <li>Chia 3×3, đặt focal ở 4 giao điểm</li>\r\n      <li>Phát triển từ thế kỷ 18</li>\r\n      <li>Dễ áp dụng, hiệu quả 80%</li>\r\n      <li>Gần với golden ratio nhưng đơn giản</li>\r\n      <li>Tiêu chuẩn trong nhiếp ảnh hiện đại</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n<!-- IMG_04: spread - so sánh 2 bức tranh golden vs thirds -->\r\n<div class=\"spread break-half\">\r\n  <div class=\"spread-text\">\r\n    <p class=\"spread-kicker\">Trong thực tế</p>\r\n    <h3 class=\"spread-title\">Khác biệt chỉ ~5%</h3>\r\n    <p>Thực tế mà nói, <strong>Rule of Thirds và Golden Ratio cho kết quả gần giống nhau</strong>. Chênh lệch toán học chỉ ~5% — không đủ để mắt thường phân biệt.</p>\r\n    <p>Vậy dùng cái nào? Với người mới học, <em>Rule of Thirds</em> dễ vẽ, dễ nhớ — chia đều 3 phần. Với người muốn tinh tế hơn, <em>Golden Ratio</em> cho cảm giác \"vừa vặn\" hơn, nhưng cần công cụ đo (lưới Fibonacci).</p>\r\n    <p>Điểm chung: cả hai đều tránh đặt focal ở <strong>đúng giữa</strong> — vị trí tẻ nhạt nhất.</p>\r\n  </div>\r\n  <div class=\"spread-img\" data-img=\"IMG_04\">\r\n    <span class=\"img-sub\">🔍 IMG_04</span>\r\n    <p class=\"img-kw\">Golden ratio vs rule of thirds overlay comparison</p>\r\n  </div>\r\n</div>\r\n\r\n<!-- ═════════════════════════════════════════════\r\n     05. ỨNG DỤNG THỰC TẾ\r\n     ═════════════════════════════════════════════ -->\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>05</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Thực hành</p>\r\n    <h2 class=\"div-title\">Quy trình bố cục</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Trước khi bắt đầu bài chính, họa sĩ chuyên nghiệp dành thời gian cho bố cục. Quy trình 4 bước:</p>\r\n\r\n<div class=\"tl\">\r\n  <div class=\"tl-item s1\">\r\n    <p class=\"tl-label\">Bước 1 · Thumbnail</p>\r\n    <h4 class=\"tl-title\">Vẽ 5-10 thumbnail nhỏ</h4>\r\n    <p class=\"tl-desc\">Mỗi cái 3-5 phút, kích thước 3-5cm. Thử các loại bố cục khác nhau: tam giác, S, chéo. Chỉ dùng 3 tông sáng tối.</p>\r\n  </div>\r\n  <div class=\"tl-item s2\">\r\n    <p class=\"tl-label\">Bước 2 · Chọn</p>\r\n    <h4 class=\"tl-title\">Chọn thumbnail đọc được tốt nhất</h4>\r\n    <p class=\"tl-desc\">Thumbnail nào ở kích thước 3cm vẫn rõ focal và hierarchy — đó là bố cục mạnh nhất. Phóng to thành bài chính.</p>\r\n  </div>\r\n  <div class=\"tl-item s3\">\r\n    <p class=\"tl-label\">Bước 3 · Grid</p>\r\n    <h4 class=\"tl-title\">Vẽ lưới bố cục lên canvas chính</h4>\r\n    <p class=\"tl-desc\">Kẻ nhẹ lưới 1/3 hoặc golden spiral. Đặt focal đúng vị trí đã chọn từ thumbnail.</p>\r\n  </div>\r\n  <div class=\"tl-item s3\">\r\n    <p class=\"tl-label\">Bước 4 · Verify</p>\r\n    <h4 class=\"tl-title\">Kiểm tra ở kích thước thumbnail</h4>\r\n    <p class=\"tl-desc\">Thu nhỏ bài đang vẽ (chụp ảnh, xem thumbnail) — nếu vẫn rõ focal, bố cục đang work. Nếu không, sửa lại.</p>\r\n  </div>\r\n</div>\r\n\r\n<!-- IMG_05: bleed - Thumbnail sketches process -->\r\n<div class=\"bleed break\" data-img=\"IMG_05\">\r\n  <span class=\"bleed-kw-label\">🔍 IMG_05</span>\r\n  <p class=\"bleed-kw\">Thumbnail sketches composition study artist process</p>\r\n  <p class=\"bleed-note\">Quy trình vẽ thumbnail — 10 phương án nhỏ trước khi chọn phương án chính</p>\r\n  <span class=\"bleed-cap\">Fig. 03 · Thumbnail workflow</span>\r\n</div>\r\n\r\n<div class=\"tips\">\r\n  <div class=\"tip\"><span class=\"tip-n\">01</span><div class=\"tip-c\"><p class=\"tip-t\">Nghiên cứu master</p><p class=\"tip-d\">Lấy tranh của Vermeer, Rembrandt, Sargent — vẽ sơ đồ bố cục. 10 tranh sẽ cho bạn mắt tốt hơn 100 giờ lý thuyết.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">02</span><div class=\"tip-c\"><p class=\"tip-t\">Squint test</p><p class=\"tip-d\">Nheo mắt nhìn thumbnail — chi tiết biến mất, chỉ còn bố cục và sắc độ. Dễ đánh giá hơn.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">03</span><div class=\"tip-c\"><p class=\"tip-t\">Đừng sợ phá quy luật</p><p class=\"tip-d\">Các bậc thầy hiểu luật rồi mới phá. Phá luật để tạo tension, surprise. Nhưng phải hiểu trước đã.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">04</span><div class=\"tip-c\"><p class=\"tip-t\">Composition before color</p><p class=\"tip-d\">Quyết định bố cục + sắc độ trước khi lên màu. Đổi bố cục ở giữa bài = vẽ lại từ đầu.</p></div></div>\r\n</div>\r\n\r\n<!-- IMG_06: spread - bad composition rescue transformed -->\r\n<div class=\"spread break-half\">\r\n  <div class=\"spread-text\">\r\n    <p class=\"spread-kicker\">Trước và sau</p>\r\n    <h3 class=\"spread-title\">Sửa bố cục = sửa cả tranh</h3>\r\n    <p>Một bài sinh viên thường có cùng một lỗi: <strong>focal point ở giữa</strong>, chủ thể không có không gian thở, nền và chủ thể cạnh tranh nhau về chi tiết.</p>\r\n    <p>Chỉ cần 3 thay đổi: (1) dời focal về 1/3 phải-trên, (2) giảm chi tiết nền bằng blur hoặc value shift, (3) thêm leading lines từ góc dưới đi lên focal — tranh đã thay đổi 180°.</p>\r\n    <p>Điểm quan trọng: <em>kỹ thuật vẽ không đổi</em>. Chỉ bố cục đổi. Đó là sức mạnh của composition.</p>\r\n  </div>\r\n  <div class=\"spread-img\" data-img=\"IMG_06\">\r\n    <span class=\"img-sub\">🔍 IMG_06</span>\r\n    <p class=\"img-kw\">Before after composition fix painting improvement</p>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"dd break-half\">\r\n  <div class=\"dd-col good\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">+</span><span class=\"dd-title\">Nên làm</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Vẽ thumbnail trước mọi bài chính</li>\r\n      <li>Chọn 1 loại bố cục phù hợp với mood</li>\r\n      <li>Đặt focal ở 1/3 hoặc giao điểm vàng</li>\r\n      <li>Test bằng squint/thumbnail throughout</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"dd-col bad\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">−</span><span class=\"dd-title\">Nên tránh</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Bắt đầu vẽ ngay không nghĩ bố cục</li>\r\n      <li>Đặt chủ thể đúng giữa khung</li>\r\n      <li>Để nền cạnh tranh chi tiết với chủ thể</li>\r\n      <li>Bỏ qua tương phản sắc độ ở focal</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"key break\">\r\n  <p class=\"key-lbl\">⭐ Điểm mấu chốt</p>\r\n  <p class=\"key-t\">Bố cục là <em>kiến trúc vô hình</em> của một bức tranh.</p>\r\n  <p class=\"key-d\">Người xem không để ý bố cục khi tranh tốt — họ chỉ \"cảm thấy đẹp\". Nhưng khi bố cục sai, họ cảm thấy \"có gì sai\" mà không nói được. Học bố cục là học kiến trúc vô hình này — kỹ năng phân biệt hoạ sĩ với thợ vẽ.</p>\r\n</div>\r\n\r\n<!-- ═════════════════════════════════════════════\r\n     06. LIÊN QUAN ĐẾN BỐ CỤC THIẾT KẾ\r\n     ═════════════════════════════════════════════ -->\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>06</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Liên quan</p>\r\n    <h2 class=\"div-title\">Khác bố cục thiết kế ở đâu?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Bố cục trong tranh và bố cục thiết kế có gốc chung nhưng mục tiêu khác nhau. Ngắn gọn:</p>\r\n\r\n<div class=\"cmp break-half\">\r\n  <div class=\"cmp-col l\">\r\n    <p class=\"cmp-lbl\">Bố cục tranh</p>\r\n    <p class=\"cmp-title\">Cảm xúc &amp; thẩm mỹ</p>\r\n    <ul class=\"cmp-list\">\r\n      <li>Ưu tiên trải nghiệm thị giác</li>\r\n      <li>Dẫn mắt qua hành trình cảm xúc</li>\r\n      <li>Không cần \"đọc\" thông tin cụ thể</li>\r\n      <li>Tự do phá quy luật vì mục đích nghệ thuật</li>\r\n      <li>Thời gian xem dài, chiêm ngưỡng</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"cmp-col r\">\r\n    <p class=\"cmp-lbl\">Bố cục thiết kế</p>\r\n    <p class=\"cmp-title\">Thông tin &amp; chức năng</p>\r\n    <ul class=\"cmp-list\">\r\n      <li>Ưu tiên truyền đạt thông tin</li>\r\n      <li>Hierarchy theo tầm quan trọng</li>\r\n      <li>Người dùng \"đọc\" và \"hành động\"</li>\r\n      <li>Tuân thủ grid và quy luật accessibility</li>\r\n      <li>Thời gian xem ngắn, liếc qua</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n<p>Muốn hiểu sâu về góc nhìn ứng dụng, xem tiếp bài <strong>\"Bố cục trong thiết kế\"</strong> — cùng chủ đề nhưng áp dụng vào poster, UI, và đồ họa thương mại.</p>\r\n\r\n<!-- ═════════════════════════════════════════════\r\n     07. FAQ\r\n     ═════════════════════════════════════════════ -->\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>07</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">FAQ</p>\r\n    <h2 class=\"div-title\">Câu hỏi thường gặp</h2>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"faq\">\r\n  <details open>\r\n    <summary>Có phải luôn luôn tuân theo quy luật bố cục?<span class=\"faq-icon\">−</span></summary>\r\n    <p>Không. Quy luật là khởi điểm, không phải ràng buộc. Picasso, Caravaggio, Turner đều phá quy luật cổ điển — nhưng họ <em>hiểu quy luật trước</em> rồi mới phá. Người mới nên nắm quy luật trước 5 năm, sau đó mới tự tin phá.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Bố cục trừu tượng có áp dụng không?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Có, thậm chí quan trọng hơn. Tranh trừu tượng không có \"chủ đề nhận diện được\" — nên bố cục và sắc độ là <em>toàn bộ</em> ngôn ngữ. Kandinsky, Mondrian tuân theo bố cục chặt chẽ dù tranh toàn hình học.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Luyện bố cục mất bao lâu?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Hiểu lý thuyết: vài tuần. \"Nhìn ra\" bố cục trong tranh: 6 tháng. Áp dụng tự nhiên khi vẽ: 1-2 năm. Bậc thầy: cả đời. Khác với kỹ thuật chì, bố cục là kỹ năng \"mắt\" — cần thời gian để chín.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Sách nào học bố cục tốt?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Andrew Loomis \"Creative Illustration\" (miễn phí PDF). Nathan Fowkes \"Color and Light for the Landscape Painter\". Greg Albert \"The Simple Secret to Better Painting\" — siêu ngắn, siêu hay. 3 cuốn đủ nền tảng.</p>\r\n  </details>\r\n</div>\r\n";

